parameters.jsCode:
const ticket = $('Normalise Ticket').first().json;
let cls;
try { cls = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); } catch { cls = {}; }
return [{ json: { ...ticket, ...cls, classified_at: new Date().toISOString() } }];

